{
  "name": "BizPlanner 3-in-1",
  "description": "Comprehensive business planning tool for Cafe, Space Rental, and Wine Bar integration including P&L analysis and BEP charting."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CafeConfig {
  avgPriceAmericano: number;
  avgPriceLatte: number;
  costAmericano: number;
  costLatte: number;
  dailySalesCount: number; // Cups per day
  ratioAmericano: number; // 0 to 1 (e.g., 0.6 for 60%)
  operatingDays: number;
}

export interface SpaceConfig {
  hourlyRate: number;
  hoursPerDay: number;
  operatingDays: number;
  utilizationRate: number; // 0 to 1
}

export interface WineConfig {
  avgTicketPrice: number; // Per table/group
  costOfGoodsSoldRate: number; // 0 to 1 (e.g., 0.35 for 35%)
  dailyTables: number;
  operatingDays: number;
}

export interface FixedCosts {
  rent: number;
  labor: number;
  utilities: number;
  internet: number;
  marketing: number;
  maintenance: number;
  misc: number;
}

export interface InitialInvestment {
  deposit: number;
  interior: number;
  equipment: number;
  design: number;
  supplies: number;
}

export interface MonthlyData {
  month: number;
  revenue: number;
  cogs: number;
  grossProfit: number;
  fixedCosts: number;
  netProfit: number;
  cumulativeProfit: number;
}

export interface GlobalConfig {
  cafe: CafeConfig;
  space: SpaceConfig;
  wine: WineConfig;
  fixed: FixedCosts;
  initial: InitialInvestment;
}

export interface TodoItem {
  id: string;
  category: string;
  task: string;
  note?: string;
  completed: boolean;
}

import React from 'react';

interface InfoCardProps {
  title: string;
  value: string;
  subValue?: string;
  icon: React.ReactNode;
  colorClass?: string;
}

export const InfoCard: React.FC<InfoCardProps> = ({ title, value, subValue, icon, colorClass = "bg-white" }) => {
  return (
    <div className={`${colorClass} p-6 rounded-xl shadow-sm border border-gray-100`}>
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-sm font-medium text-gray-500">{title}</h3>
        <div className="text-gray-400">{icon}</div>
      </div>
      <div className="text-2xl font-bold text-gray-900">{value}</div>
      {subValue && <div className="text-xs font-medium text-gray-500 mt-1">{subValue}</div>}
    </div>
  );
};

import React, { useState } from 'react';
import { ChevronDown, ChevronUp } from 'lucide-react';

interface InputSectionProps {
  title: string;
  children: React.ReactNode;
  isOpenDefault?: boolean;
}

export const InputSection: React.FC<InputSectionProps> = ({ title, children, isOpenDefault = false }) => {
  const [isOpen, setIsOpen] = useState(isOpenDefault);

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden mb-4">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full px-6 py-4 flex items-center justify-between bg-gray-50 hover:bg-gray-100 transition-colors"
      >
        <span className="font-semibold text-gray-800">{title}</span>
        {isOpen ? <ChevronUp size={20} className="text-gray-500" /> : <ChevronDown size={20} className="text-gray-500" />}
      </button>
      {isOpen && <div className="p-6 border-t border-gray-200">{children}</div>}
    </div>
  );
};

import React from 'react';
import { MonthlyData } from '../types';

interface FinancialTableProps {
  data: MonthlyData[];
}

export const FinancialTable: React.FC<FinancialTableProps> = ({ data }) => {
  const formatCurrency = (val: number) => Math.round(val).toLocaleString();

  return (
    <div className="overflow-x-auto bg-white rounded-xl shadow-sm border border-gray-200">
      <table className="w-full text-sm text-right">
        <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
          <tr>
            <th className="px-4 py-3 text-left sticky left-0 bg-gray-50 border-r border-gray-200 w-32">구분 (단위:원)</th>
            {data.map((row) => (
              <th key={row.month} className="px-4 py-3 min-w-[100px]">M+{row.month}</th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          <tr>
            <td className="px-4 py-3 text-left font-medium sticky left-0 bg-white border-r border-gray-200">매출 합계</td>
            {data.map((row) => (
              <td key={row.month} className="px-4 py-3 text-blue-600 font-semibold">{formatCurrency(row.revenue)}</td>
            ))}
          </tr>
          <tr>
            <td className="px-4 py-3 text-left sticky left-0 bg-white border-r border-gray-200 text-gray-500">원가 (재료비)</td>
            {data.map((row) => (
              <td key={row.month} className="px-4 py-3 text-red-400">-{formatCurrency(row.cogs)}</td>
            ))}
          </tr>
          <tr className="bg-gray-50/50">
            <td className="px-4 py-3 text-left font-medium sticky left-0 bg-gray-50 border-r border-gray-200">매출총이익</td>
            {data.map((row) => (
              <td key={row.month} className="px-4 py-3 font-medium">{formatCurrency(row.grossProfit)}</td>
            ))}
          </tr>
          <tr>
            <td className="px-4 py-3 text-left sticky left-0 bg-white border-r border-gray-200 text-gray-500">고정비 (임대/인건)</td>
            {data.map((row) => (
              <td key={row.month} className="px-4 py-3 text-red-400">-{formatCurrency(row.fixedCosts)}</td>
            ))}
          </tr>
          <tr className="bg-blue-50/50 border-t-2 border-blue-100">
            <td className="px-4 py-3 text-left font-bold text-blue-900 sticky left-0 bg-blue-50 border-r border-blue-200">순이익</td>
            {data.map((row) => (
              <td key={row.month} className={`px-4 py-3 font-bold ${row.netProfit >= 0 ? 'text-blue-700' : 'text-red-600'}`}>
                {formatCurrency(row.netProfit)}
              </td>
            ))}
          </tr>
          <tr className="bg-gray-100/50">
             <td className="px-4 py-3 text-left font-bold text-gray-700 sticky left-0 bg-gray-100 border-r border-gray-200">누적 손익 (BEP)</td>
             {data.map((row) => (
              <td key={row.month} className={`px-4 py-3 font-bold ${row.cumulativeProfit >= 0 ? 'text-green-600' : 'text-red-500'}`}>
                {formatCurrency(row.cumulativeProfit)}
              </td>
            ))}
          </tr>
        </tbody>
      </table>
    </div>
  );
};

import React from 'react';

interface NumberInputProps {
  label: string;
  value: number;
  onChange: (val: number) => void;
  unit?: string;
  step?: number;
}

export const NumberInput: React.FC<NumberInputProps> = ({ label, value, onChange, unit, step = 1 }) => (
  <div className="flex flex-col">
    <label className="text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">{label}</label>
    <div className="relative">
      <input
        type="number"
        className="w-full p-2 pr-8 border border-gray-300 rounded-md focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-right font-mono"
        value={value}
        onChange={(e) => onChange(Number(e.target.value))}
        step={step}
      />
      {unit && <span className="absolute right-3 top-2 text-gray-400 text-sm">{unit}</span>}
    </div>
  </div>
);

import React, { useState, useMemo, useEffect } from 'react';
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ComposedChart,
  ReferenceLine
} from 'recharts';
import {
  Coffee,
  Home,
  Wine,
  Calculator,
  CheckSquare,
  TrendingUp,
  DollarSign,
  AlertCircle
} from 'lucide-react';

import { DEFAULT_CONFIG, INITIAL_TODOS } from './constants';
import { GlobalConfig, MonthlyData, TodoItem } from './types';
import { InfoCard } from './components/InfoCard';
import { InputSection } from './components/InputSection';
import { FinancialTable } from './components/FinancialTable';
import { NumberInput } from './components/Inputs';

enum Tab {
  DASHBOARD = 'dashboard',
  PLANNER = 'planner',
  TODO = 'todo',
}

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);
  const [config, setConfig] = useState<GlobalConfig>(DEFAULT_CONFIG);
  const [todos, setTodos] = useState<TodoItem[]>(INITIAL_TODOS);
  const [projectionMonths, setProjectionMonths] = useState(12);

  // --- Calculations ---

  const monthlyData: MonthlyData[] = useMemo(() => {
    const data: MonthlyData[] = [];
    const totalInitialCost =
      config.initial.deposit +
      config.initial.interior +
      config.initial.equipment +
      config.initial.design +
      config.initial.supplies;

    let cumulativeProfit = -totalInitialCost;

    for (let m = 1; m <= projectionMonths; m++) {
      // 1. Cafe Calculations
      const cafeRevenue =
        (config.cafe.avgPriceAmericano * config.cafe.ratioAmericano +
          config.cafe.avgPriceLatte * (1 - config.cafe.ratioAmericano)) *
        config.cafe.dailySalesCount *
        config.cafe.operatingDays;

      const cafeCOGS =
        (config.cafe.costAmericano * config.cafe.ratioAmericano +
          config.cafe.costLatte * (1 - config.cafe.ratioAmericano)) *
        config.cafe.dailySalesCount *
        config.cafe.operatingDays;

      // 2. Space Rental Calculations
      const spaceRevenue =
        config.space.hourlyRate *
        config.space.hoursPerDay *
        config.space.utilizationRate *
        config.space.operatingDays;
      const spaceCOGS = 0; // Assuming almost zero variable cost per booking

      // 3. Wine Bar Calculations
      const wineRevenue =
        config.wine.avgTicketPrice *
        config.wine.dailyTables *
        config.wine.operatingDays;
      const wineCOGS = wineRevenue * config.wine.costOfGoodsSoldRate;

      // Aggregations
      const totalRevenue = cafeRevenue + spaceRevenue + wineRevenue;
      const totalCOGS = cafeCOGS + spaceCOGS + wineCOGS;
      const grossProfit = totalRevenue - totalCOGS;

      const totalFixedCosts =
        config.fixed.rent +
        config.fixed.labor +
        config.fixed.utilities +
        config.fixed.internet +
        config.fixed.marketing +
        config.fixed.maintenance +
        config.fixed.misc;

      const netProfit = grossProfit - totalFixedCosts;

      cumulativeProfit += netProfit;

      data.push({
        month: m,
        revenue: totalRevenue,
        cogs: totalCOGS,
        grossProfit,
        fixedCosts: totalFixedCosts,
        netProfit,
        cumulativeProfit,
      });
    }
    return data;
  }, [config, projectionMonths]);

  const bepMonth = useMemo(() => {
    const match = monthlyData.find(d => d.cumulativeProfit >= 0);
    return match ? `M+${match.month}` : '미도달';
  }, [monthlyData]);

  const totalInvestment = useMemo(() => {
    return Object.values(config.initial).reduce((a, b) => a + b, 0);
  }, [config.initial]);

  // --- Handlers ---
  const toggleTodo = (id: string) => {
    setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const handleConfigChange = (section: keyof GlobalConfig, field: string, value: number) => {
    setConfig(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        [field]: value
      }
    }));
  };

  // --- Renders ---

  const renderDashboard = () => (
    <div className="space-y-6">
      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <InfoCard
          title="월 예상 매출"
          value={`₩${Math.round(monthlyData[0]?.revenue / 10000).toLocaleString()}만`}
          subValue="3가지 사업 합산"
          icon={<TrendingUp className="text-blue-500" />}
        />
        <InfoCard
          title="월 예상 순이익"
          value={`₩${Math.round(monthlyData[0]?.netProfit / 10000).toLocaleString()}만`}
          subValue={`마진율 ${Math.round((monthlyData[0]?.netProfit / monthlyData[0]?.revenue) * 100)}%`}
          icon={<DollarSign className="text-green-500" />}
        />
        <InfoCard
          title="초기 투자비용"
          value={`₩${Math.round(totalInvestment / 10000).toLocaleString()}만`}
          subValue="보증금 포함"
          icon={<Calculator className="text-purple-500" />}
        />
        <InfoCard
          title="손익분기점 (BEP)"
          value={bepMonth}
          subValue={bepMonth !== '미도달' ? '누적 수익 전환 시점' : '1년 내 달성 불가'}
          icon={<AlertCircle className="text-orange-500" />}
        />
      </div>

      {/* Charts */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
        <h2 className="text-lg font-bold text-gray-800 mb-6">BEP 시점 및 수익 구조 분석</h2>
        <div className="h-[400px] w-full">
          <ResponsiveContainer width="100%" height="100%">
            <ComposedChart data={monthlyData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" />
              <XAxis dataKey="month" tickFormatter={(val) => `M+${val}`} stroke="#9CA3AF" />
              <YAxis yAxisId="left" orientation="left" stroke="#9CA3AF" tickFormatter={(val) => `${val / 10000}만`} />
              <YAxis yAxisId="right" orientation="right" stroke="#9CA3AF" tickFormatter={(val) => `${val / 10000}만`} />
              <Tooltip
                formatter={(value: number) => `₩${value.toLocaleString()}`}
                contentStyle={{ backgroundColor: '#fff', borderRadius: '8px', border: '1px solid #e5e7eb' }}
              />
              <Legend wrapperStyle={{ paddingTop: '20px' }} />
              <ReferenceLine y={0} yAxisId="right" stroke="#000" strokeDasharray="3 3" />
              <Bar yAxisId="left" dataKey="netProfit" name="월 순이익" fill="#3B82F6" barSize={30} radius={[4, 4, 0, 0]} />
              <Line yAxisId="right" type="monotone" dataKey="cumulativeProfit" name="누적 손익" stroke="#F97316" strokeWidth={3} dot={{ r: 4 }} />
            </ComposedChart>
          </ResponsiveContainer>
        </div>
      </div>

       {/* Detailed Table */}
       <div className="space-y-4">
        <h3 className="text-lg font-bold text-gray-800">월간 재무 상세 (Monthly P&L)</h3>
        <FinancialTable data={monthlyData} />
      </div>
    </div>
  );

  const renderPlanner = () => (
    <div className="space-y-6 max-w-4xl mx-auto">
      <div className="bg-blue-50 p-4 rounded-lg text-blue-800 text-sm mb-6">
        <p>💡 각 항목의 수치를 조정하면 대시보드의 차트와 재무표가 실시간으로 변경됩니다.</p>
      </div>

      <InputSection title="☕ 카페 (Cafe) 설정" isOpenDefault={true}>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <NumberInput label="아메리카노 판매가" value={config.cafe.avgPriceAmericano} onChange={(v) => handleConfigChange('cafe', 'avgPriceAmericano', v)} unit="원" />
          <NumberInput label="아메리카노 원가" value={config.cafe.costAmericano} onChange={(v) => handleConfigChange('cafe', 'costAmericano', v)} unit="원" />
          <NumberInput label="판매 비중 (아메리카노)" value={config.cafe.ratioAmericano} onChange={(v) => handleConfigChange('cafe', 'ratioAmericano', v)} step={0.1} />
          <NumberInput label="라떼 판매가" value={config.cafe.avgPriceLatte} onChange={(v) => handleConfigChange('cafe', 'avgPriceLatte', v)} unit="원" />
          <NumberInput label="라떼 원가" value={config.cafe.costLatte} onChange={(v) => handleConfigChange('cafe', 'costLatte', v)} unit="원" />
          <NumberInput label="일일 예상 판매 잔수" value={config.cafe.dailySalesCount} onChange={(v) => handleConfigChange('cafe', 'dailySalesCount', v)} unit="잔" />
        </div>
      </InputSection>

      <InputSection title="🏠 공간대여 (Space Rental) 설정" isOpenDefault={true}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <NumberInput label="시간당 대여료" value={config.space.hourlyRate} onChange={(v) => handleConfigChange('space', 'hourlyRate', v)} unit="원" />
          <NumberInput label="일 가용 시간" value={config.space.hoursPerDay} onChange={(v) => handleConfigChange('space', 'hoursPerDay', v)} unit="시간" />
          <NumberInput label="월 영업일수" value={config.space.operatingDays} onChange={(v) => handleConfigChange('space', 'operatingDays', v)} unit="일" />
          <NumberInput label="가동률 (예약률)" value={config.space.utilizationRate} onChange={(v) => handleConfigChange('space', 'utilizationRate', v)} step={0.1} />
        </div>
      </InputSection>

      <InputSection title="🍷 와인바 (Wine Bar) 설정" isOpenDefault={true}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <NumberInput label="테이블당 평균 단가" value={config.wine.avgTicketPrice} onChange={(v) => handleConfigChange('wine', 'avgTicketPrice', v)} unit="원" />
          <NumberInput label="일 평균 테이블 수" value={config.wine.dailyTables} onChange={(v) => handleConfigChange('wine', 'dailyTables', v)} unit="팀" />
          <NumberInput label="원가율 (안주+주류)" value={config.wine.costOfGoodsSoldRate} onChange={(v) => handleConfigChange('wine', 'costOfGoodsSoldRate', v)} step={0.01} />
          <NumberInput label="월 영업일수" value={config.wine.operatingDays} onChange={(v) => handleConfigChange('wine', 'operatingDays', v)} unit="일" />
        </div>
      </InputSection>

      <InputSection title="🏢 고정비 및 초기투자 (Fixed & Initial Cost)">
        <div className="space-y-6">
            <h4 className="font-medium text-gray-700 border-b pb-2">월 고정 비용</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <NumberInput label="월 임대료" value={config.fixed.rent} onChange={(v) => handleConfigChange('fixed', 'rent', v)} unit="원" />
                <NumberInput label="인건비 (총액)" value={config.fixed.labor} onChange={(v) => handleConfigChange('fixed', 'labor', v)} unit="원" />
                <NumberInput label="공과금 (수도/전기)" value={config.fixed.utilities} onChange={(v) => handleConfigChange('fixed', 'utilities', v)} unit="원" />
                <NumberInput label="마케팅비" value={config.fixed.marketing} onChange={(v) => handleConfigChange('fixed', 'marketing', v)} unit="원" />
            </div>

            <h4 className="font-medium text-gray-700 border-b pb-2 pt-4">초기 투자 비용</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <NumberInput label="보증금" value={config.initial.deposit} onChange={(v) => handleConfigChange('initial', 'deposit', v)} unit="원" />
                <NumberInput label="인테리어" value={config.initial.interior} onChange={(v) => handleConfigChange('initial', 'interior', v)} unit="원" />
                <NumberInput label="설비/집기" value={config.initial.equipment} onChange={(v) => handleConfigChange('initial', 'equipment', v)} unit="원" />
                <NumberInput label="디자인/브랜딩" value={config.initial.design} onChange={(v) => handleConfigChange('initial', 'design', v)} unit="원" />
            </div>
        </div>
      </InputSection>
    </div>
  );

  const renderTodo = () => {
    // Group by category
    const groupedTodos = todos.reduce((acc, todo) => {
      if (!acc[todo.category]) acc[todo.category] = [];
      acc[todo.category].push(todo);
      return acc;
    }, {} as Record<string, TodoItem[]>);

    return (
      <div className="max-w-3xl mx-auto space-y-8">
        <div className="flex justify-between items-end border-b border-gray-200 pb-4">
            <h2 className="text-2xl font-bold text-gray-800">개업 준비 체크리스트</h2>
            <div className="text-gray-500 text-sm">
                진행률: {Math.round((todos.filter(t => t.completed).length / todos.length) * 100)}%
            </div>
        </div>

        {Object.entries(groupedTodos).map(([category, items]) => (
          <div key={category} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
            <div className="bg-gray-50 px-6 py-3 font-semibold text-gray-700 border-b border-gray-200">
              {category}
            </div>
            <div className="divide-y divide-gray-100">
              {items.map((item) => (
                <div key={item.id} className="flex items-center p-4 hover:bg-blue-50 transition-colors cursor-pointer" onClick={() => toggleTodo(item.id)}>
                  <div className={`w-6 h-6 rounded border flex items-center justify-center mr-4 transition-all ${item.completed ? 'bg-blue-500 border-blue-500' : 'border-gray-300 bg-white'}`}>
                    {item.completed && <CheckSquare className="text-white w-4 h-4" />}
                  </div>
                  <div className="flex-1">
                    <div className={`font-medium ${item.completed ? 'text-gray-400 line-through' : 'text-gray-800'}`}>
                      {item.task}
                    </div>
                    {item.note && <div className="text-xs text-gray-500 mt-0.5">{item.note}</div>}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans text-gray-900 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center space-x-2">
              <div className="bg-blue-600 p-2 rounded-lg">
                <Coffee className="text-white h-5 w-5" />
              </div>
              <span className="font-bold text-xl tracking-tight text-gray-900">BizPlanner <span className="text-blue-600 font-light">3-in-1</span></span>
            </div>

            {/* Nav Tabs */}
            <nav className="flex space-x-1 bg-gray-100 p-1 rounded-lg">
              {[
                { id: Tab.DASHBOARD, label: '대시보드', icon: <TrendingUp size={16} /> },
                { id: Tab.PLANNER, label: '계획 설정', icon: <Calculator size={16} /> },
                { id: Tab.TODO, label: '체크리스트', icon: <CheckSquare size={16} /> },
              ].map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as Tab)}
                  className={`
                    flex items-center space-x-2 px-4 py-2 rounded-md text-sm font-medium transition-all
                    ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}
                  `}
                >
                  {tab.icon}
                  <span className="hidden sm:inline">{tab.label}</span>
                </button>
              ))}
            </nav>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {activeTab === Tab.DASHBOARD && renderDashboard()}
        {activeTab === Tab.PLANNER && renderPlanner()}
        {activeTab === Tab.TODO && renderTodo()}
      </main>
    </div>
  );
}

