enum Tab {
  DASHBOARD = 'dashboard',
  PLANNER = 'planner',
  TODO = 'todo',
}

export default function App() {
  const [activeTab, setActiveTab] = useState<Tab>(Tab.DASHBOARD);
  const [config, setConfig] = useState<GlobalConfig>(DEFAULT_CONFIG);
  const [todos, setTodos] = useState<TodoItem[]>(INITIAL_TODOS);
  const [projectionMonths, setProjectionMonths] = useState(12);
  const [cafeDetailsOpen, setCafeDetailsOpen] = useState(true);

  // --- Helper: Calculate Cafe Unit Costs dynamically ---
  const cafeUnitCosts = useMemo(() => {
    const { beanPricePerKg, milkPricePerL, takeoutRatio } = config.cafe;

    // Ingredients Cost
    const beanCost = (beanPricePerKg / 1000) * CAFE_UNIT_COSTS.BEAN_GRAMS;
    const milkCost = (milkPricePerL / 1000) * CAFE_UNIT_COSTS.MILK_ML;

    // 1. Takeout Costs (Based on Image 1)
    // Carrier probability 0.3 applied to 60 won = 18 won in data, but let's use fixed 18 for simplicity matching table
    const takeoutHotBase = 
      CAFE_UNIT_COSTS.HOT_CUP + CAFE_UNIT_COSTS.HOT_LID + CAFE_UNIT_COSTS.STICK + 
      CAFE_UNIT_COSTS.HOLDER + CAFE_UNIT_COSTS.CARRIER + CAFE_UNIT_COSTS.WIPE + CAFE_UNIT_COSTS.NAPKIN;

    const takeoutIceBase = 
      CAFE_UNIT_COSTS.ICE_CUP + CAFE_UNIT_COSTS.ICE_LID + CAFE_UNIT_COSTS.STRAW + 
      CAFE_UNIT_COSTS.HOLDER + CAFE_UNIT_COSTS.CARRIER + CAFE_UNIT_COSTS.WIPE + CAFE_UNIT_COSTS.NAPKIN;

    // 2. Store Costs (Based on Image 2 - Dishwashing replaces disposables partly)
    // Note: Image 2 shows some disposables are removed, added Dishwashing (60)
    const storeHotBase = 
      CAFE_UNIT_COSTS.STICK + CAFE_UNIT_COSTS.WIPE + CAFE_UNIT_COSTS.NAPKIN + CAFE_UNIT_COSTS.DISHWASHING;

    const storeIceBase = 
      CAFE_UNIT_COSTS.STRAW + CAFE_UNIT_COSTS.WIPE + CAFE_UNIT_COSTS.NAPKIN + CAFE_UNIT_COSTS.DISHWASHING;

    // 3. Assemble Product Costs
    // Assuming 50:50 Hot:Ice ratio for general Americano/Latte average if not specified
    // Americano = Base + Bean + Water + (Ice if Ice)
    const costAmTakeoutHot = takeoutHotBase + beanCost + CAFE_UNIT_COSTS.WATER;
    const costAmTakeoutIce = takeoutIceBase + beanCost + CAFE_UNIT_COSTS.WATER + CAFE_UNIT_COSTS.ICE;
    const costAmStoreHot = storeHotBase + beanCost + CAFE_UNIT_COSTS.WATER;
    const costAmStoreIce = storeIceBase + beanCost + CAFE_UNIT_COSTS.WATER + CAFE_UNIT_COSTS.ICE;

    const avgCostAmTakeout = (costAmTakeoutHot + costAmTakeoutIce) / 2;
    const avgCostAmStore = (costAmStoreHot + costAmStoreIce) / 2;

    // Weighted Average Americano Cost
    const finalCostAmericano = (avgCostAmTakeout * takeoutRatio) + (avgCostAmStore * (1 - takeoutRatio));

    // Latte = Base + Bean + Milk (No Water usually, but Table says 30 Water, so we keep it to match table logic or remove? 
    // Table 1 for Latte: Water 30, Milk 375. We will follow table.)
    const costLatteTakeoutHot = takeoutHotBase + beanCost + milkCost + CAFE_UNIT_COSTS.WATER;
    const costLatteTakeoutIce = takeoutIceBase + beanCost + milkCost + CAFE_UNIT_COSTS.WATER + CAFE_UNIT_COSTS.ICE;
    const costLatteStoreHot = storeHotBase + beanCost + milkCost + CAFE_UNIT_COSTS.WATER;
    const costLatteStoreIce = storeIceBase + beanCost + milkCost + CAFE_UNIT_COSTS.WATER + CAFE_UNIT_COSTS.ICE;

    const avgCostLatteTakeout = (costLatteTakeoutHot + costLatteTakeoutIce) / 2;
    const avgCostLatteStore = (costLatteStoreHot + costLatteStoreIce) / 2;

    const finalCostLatte = (avgCostLatteTakeout * takeoutRatio) + (avgCostLatteStore * (1 - takeoutRatio));

    return {
      beanCost,
      milkCost,
      finalCostAmericano,
      finalCostLatte,
      detail: {
        takeout: { am: avgCostAmTakeout, latte: avgCostLatteTakeout },
        store: { am: avgCostAmStore, latte: avgCostLatteStore }
      }
    };
  }, [config.cafe]);

  // --- Calculations ---

  const monthlyData: MonthlyData[] = useMemo(() => {
    const data: MonthlyData[] = [];
    const totalInitialCost =
      config.initial.deposit +
      config.initial.interior +
      config.initial.equipment +
      config.initial.design +
      config.initial.supplies;

    let cumulativeProfit = -totalInitialCost;

    for (let m = 1; m <= projectionMonths; m++) {
      // 1. Cafe Calculations
      const cafeRevenue =
        (config.cafe.avgPriceAmericano * config.cafe.ratioAmericano +
          config.cafe.avgPriceLatte * (1 - config.cafe.ratioAmericano)) *
        config.cafe.dailySalesCount *
        config.cafe.operatingDays;

      // Use calculated dynamic costs
      const cafeCOGS =
        (cafeUnitCosts.finalCostAmericano * config.cafe.ratioAmericano +
          cafeUnitCosts.finalCostLatte * (1 - config.cafe.ratioAmericano)) *
        config.cafe.dailySalesCount *
        config.cafe.operatingDays;

      // 2. Space Rental Calculations
      const spaceRevenue =
        config.space.hourlyRate *
        config.space.hoursPerDay *
        config.space.utilizationRate *
        config.space.operatingDays;
      const spaceCOGS = 0; // Assuming almost zero variable cost per booking

      // 3. Wine Bar Calculations
      const wineRevenue =
        config.wine.avgTicketPrice *
        config.wine.dailyTables *
        config.wine.operatingDays;
      const wineCOGS = wineRevenue * config.wine.costOfGoodsSoldRate;

      // Aggregations
      const totalRevenue = cafeRevenue + spaceRevenue + wineRevenue;
      const totalCOGS = cafeCOGS + spaceCOGS + wineCOGS;
      const grossProfit = totalRevenue - totalCOGS;

      const totalFixedCosts =
        config.fixed.rent +
        config.fixed.labor +
        config.fixed.utilities +
        config.fixed.internet +
        config.fixed.marketing +
        config.fixed.maintenance +
        config.fixed.misc;

      const netProfit = grossProfit - totalFixedCosts;

      cumulativeProfit += netProfit;

      data.push({
        month: m,
        revenue: totalRevenue,
        cogs: totalCOGS,
        grossProfit,
        fixedCosts: totalFixedCosts,
        netProfit,
        cumulativeProfit,
      });
    }
    return data;
  }, [config, projectionMonths, cafeUnitCosts]);

  const bepMonth = useMemo(() => {
    const match = monthlyData.find(d => d.cumulativeProfit >= 0);
    return match ? `M+${match.month}` : '미도달';
  }, [monthlyData]);

  const totalInvestment = useMemo(() => {
    return Object.values(config.initial).reduce((a, b) => a + b, 0);
