                  <NumberInput label="테이크아웃 비율 (0~1)" value={config.cafe.takeoutRatio} onChange={(v) => handleConfigChange('cafe', 'takeoutRatio', v)} step={0.1} />
                  <NumberInput label="아메리카노 판매 비중" value={config.cafe.ratioAmericano} onChange={(v) => handleConfigChange('cafe', 'ratioAmericano', v)} step={0.1} />
                  <NumberInput label="일일 총 판매 잔수" value={config.cafe.dailySalesCount} onChange={(v) => handleConfigChange('cafe', 'dailySalesCount', v)} unit="잔" />
               </div>
            </div>

            {/* 2. Detailed Cost Breakdown Table */}
            <div>
              <h4 className="font-bold text-gray-800 mb-3 text-sm uppercase tracking-wide">1잔당 원가 상세 분석 (Hot/Ice 평균)</h4>
              <div className="overflow-x-auto border border-gray-200 rounded-lg">
                <table className="w-full text-sm text-right">
                    <thead className="bg-gray-100 text-gray-700">
                        <tr>
                            <th className="px-4 py-2 text-left w-32">항목</th>
                            <th className="px-4 py-2 bg-blue-50 text-blue-800">테이크아웃 (Takeout)</th>
